import './App.css';
import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Box, Container, Button, Flex, Text, Section, Heading} from "@radix-ui/themes";

function App() {
  return (
    <Theme appearance="dark" accentColor="yellow" panelBackground="solid" radius="full">
      <ThemePanel />
      <Container size="4">
        <Section css={{ py: 4 }} gap="10">
          <Flex gap="4" direction="column">
            <Heading mt="5" size="9">Eduardo Fawke</Heading>
            <Heading weight="medium" mb="4" size="6">Full Stack Web Developer</Heading>
          </Flex>
        </Section>
      </Container>
    </Theme>
  );
}

export default App;
